import{_ as h,y as o,a as r,o as a,ag as c,D as i,g}from"./chunks/framework.RVu0gECZ.js";const b=JSON.parse('{"title":"Quyền dựa trên vai trò","description":"","frontmatter":{},"headers":[],"relativePath":"b2b-ecommerce-platform/role-based-permissions.md","filePath":"b2b-ecommerce-platform/role-based-permissions.md","lastUpdated":1775811487000}'),p={name:"b2b-ecommerce-platform/role-based-permissions.md"};function e(s,n,m,u,d,l){const t=o("ImagePopup");return a(),r("div",null,[n[0]||(n[0]=c('<h1 id="quyen-dua-tren-vai-tro" tabindex="-1">Quyền dựa trên vai trò <a class="header-anchor" href="#quyen-dua-tren-vai-tro" aria-label="Permalink to &quot;Quyền dựa trên vai trò&quot;">​</a></h1><p>Tính năng Quyền dựa trên vai trò cho phép các công ty tạo các vai trò tùy chỉnh và xác định những gì mỗi người dùng có thể truy cập trong tổ chức.</p><p>Điều này giúp đảm bảo rằng mỗi người dùng chỉ có quyền truy cập vào các tính năng liên quan đến trách nhiệm của họ.</p><h3 id="cac-buoc-tao-vai-tro" tabindex="-1">Các bước tạo vai trò <a class="header-anchor" href="#cac-buoc-tao-vai-tro" aria-label="Permalink to &quot;Các bước tạo vai trò&quot;">​</a></h3><p><strong>Bước: 1</strong> Đi tới <strong>Tài khoản → Hồ sơ → Vai trò</strong> của tôi từ cửa hàng công ty.</p><p>Trang <strong>Vai trò của công ty</strong> sẽ xuất hiện, hiển thị tất cả các vai trò hiện có cùng với các tùy chọn để tìm kiếm, lọc hoặc quản lý chúng.</p><p>Như được hiển thị trong hình bên dưới, bạn có thể xem danh sách các vai trò hiện có, chẳng hạn như “Quản trị viên”.</p>',7)),i(t,{src:"/images/b2b-ecommerce-platform/1-company-roles.png",alt:"Super Admin Login"}),n[1]||(n[1]=c("<p><strong>Bước: 2</strong> Nhấp vào Thêm vai trò để mở biểu mẫu Thêm vai trò công ty.</p><p><strong>Bước: 3</strong> Điền các thông tin sau:</p><p><strong>A) Tên –</strong> Nhập tên của vai trò (ví dụ: Quản trị viên, Người quản lý, Người mua).</p><p><strong>B) Mô tả –</strong> Thêm mô tả ngắn để nêu rõ mục đích của vai trò.</p><p><strong>Bước: 4</strong> Trong Kiểm soát truy cập, chọn cấp độ truy cập bạn muốn chỉ định:</p><p><strong>A) Tất cả các quyền –</strong> Cấp quyền truy cập đầy đủ vào tất cả các tính năng có sẵn của công ty.</p><p><strong>B) Quyền tùy chỉnh –</strong> Cho phép bạn chọn thủ công các quyền cụ thể cho vai trò dựa trên nhu cầu của công ty bạn.</p><p><strong>Bước: 5</strong> Khi bạn đã thiết lập cài đặt kiểm soát truy cập, hãy nhấp vào Lưu vai trò để tạo vai trò mới. Như thể hiện trong hình ảnh dưới đây,</p>",8)),i(t,{src:"/images/b2b-ecommerce-platform/2-add-company-role.png",alt:"Super Admin Login"}),n[2]||(n[2]=c('<p><strong>Lưu ý:</strong></p><ul><li><p>Bạn có thể chỉnh sửa hoặc xóa các vai trò hiện có bất kỳ lúc nào trên cùng một trang.</p></li><li><p>Sau khi tạo một vai trò, vai trò đó có thể được chỉ định cho người dùng trong khi thêm hoặc chỉnh sửa người dùng công ty.</p></li></ul><h3 id="quan-ly-nguoi-dung-cong-ty" tabindex="-1">Quản lý người dùng công ty <a class="header-anchor" href="#quan-ly-nguoi-dung-cong-ty" aria-label="Permalink to &quot;Quản lý người dùng công ty&quot;">​</a></h3><p>Tính năng Quản lý người dùng của công ty cho phép các công ty thêm và quản lý nhiều người dùng trong tài khoản của họ.</p><p>Mỗi người dùng có thể có vai trò và cấp độ truy cập xác định, giúp doanh nghiệp duy trì quyền kiểm soát phù hợp trong tổ chức của mình.</p><h4 id="cac-buoc-đe-them-nguoi-dung-cong-ty-moi" tabindex="-1">Các bước để thêm người dùng công ty mới <a class="header-anchor" href="#cac-buoc-đe-them-nguoi-dung-cong-ty-moi" aria-label="Permalink to &quot;Các bước để thêm người dùng công ty mới&quot;">​</a></h4><p><strong>Bước: 1</strong> Đi tới Tài khoản của tôi → Hồ sơ → Người dùng từ cửa hàng công ty.</p><p><strong>Bước: 2</strong> Trang Người dùng Công ty sẽ xuất hiện, hiển thị tất cả người dùng hiện có với các tùy chọn để tìm kiếm, lọc hoặc quản lý họ.</p><p>Như minh họa trong hình bên dưới, ban đầu danh sách sẽ trống nếu không có người dùng nào được tạo.</p>',9)),i(t,{src:"/images/b2b-ecommerce-platform/3-company-users.png",alt:"Super Admin Login"}),n[3]||(n[3]=c("<p><strong>Bước: 3</strong> Nhấp vào Thêm người dùng để mở biểu mẫu Thêm người dùng công ty.</p><p><strong>Bước: 4</strong> Điền các thông tin sau:</p><p><em>A) Tên –</em> Nhập tên của người dùng.</p><p><em>B) Họ –</em> Nhập họ của người dùng.</p><p><em>C) Email –</em> Nhập địa chỉ email hợp lệ.</p><p><em>D) Điện thoại –</em> Cung cấp số liên lạc của người dùng.</p><p><em>E) Giới tính –</em> Chọn giới tính của người dùng.</p><p><em>F) Ngày sinh –</em> Nhập ngày sinh của người dùng.</p><p><em>G) Vai trò –</em> Chọn vai trò thích hợp từ danh sách các vai trò đã tạo.</p><p><em>H) Trạng thái –</em> Đặt tài khoản của người dùng là Hoạt động hoặc Không hoạt động.</p><p><em>I) Bị tạm dừng –</em> Nếu được bật, người dùng có thể đăng nhập nhưng không thể tiến hành thanh toán. Một thông báo sẽ hiển thị: “Tài khoản của bạn đã bị đình chỉ”.</p><p><strong>Bước: 5</strong> Tùy chọn, tải lên <strong>Hình ảnh hoặc Video hồ sơ</strong> cho người dùng.</p><p><strong>Bước: 6</strong> Sau khi điền tất cả thông tin được yêu cầu, hãy nhấp vào <strong>Lưu người dùng</strong> để thêm người dùng mới của công ty. Như thể hiện trong hình ảnh dưới đây.</p>",13)),i(t,{src:"/images/b2b-ecommerce-platform/4-add-company-user.png",alt:"Super Admin Login"}),n[4]||(n[4]=g("p",null,[g("strong",null,"Ghi chú:")],-1)),n[5]||(n[5]=g("p",null,"Quản trị viên công ty có thể chỉnh sửa, tạm dừng hoặc xóa người dùng bất kỳ lúc nào.",-1)),n[6]||(n[6]=g("p",null,"Quyền truy cập vào các tính năng tùy thuộc vào quyền vai trò được chỉ định cho mỗi người dùng.",-1))])}const v=h(p,[["render",e]]);export{b as __pageData,v as default};
